INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00749', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起浸潤性角膜炎（infiltrativekeratitis）之敘述，下列何者錯誤？', '["軟式隱形眼鏡配戴者常發生此併發症，大多發生在角膜中央區域", "隱形眼鏡護理藥水產生之過敏反應會產生浸潤性角膜炎", "戴基弧太陡或無滑動的隱形眼鏡也會產生浸潤性角膜炎", "角膜會局部水腫及有發炎細胞的聚集，使上皮細胞浸潤而呈現混濁半透明狀態"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00750', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關配戴透氣硬式隱形眼鏡與棘狀阿米巴角膜炎（Acanthamoeba keratitis）之敘述，下列何者正確？①隱', '["夜戴型角膜塑形鏡片與棘狀阿米巴角膜炎 的發生有相關性", "用手指搓洗鏡片可以降低棘狀阿米巴菌在鏡面的附著", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00751', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一位配戴隱形眼鏡經常導致眼結膜充血不適的上班女性，你懷疑此患者可能有乾眼症，下列那一項的測 試結果可以支持乾眼症的診斷？', '["Schirmer’s淚液測試>10mm/5分鐘", "非侵入式淚液破裂時間（tearfilmbreak-uptime）<10秒", "下眼瞼淚稜鏡高度（tearmeniscusheight）>3mm", "裂隙燈檢查發現角膜新生血管大約1個象限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00752', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於角膜塑型術（orthokeratology）併發角膜炎（keratitis）之敘述，下列何者正確？', '["最常見的微生物感染為綠膿桿菌（Pseudomonasaeruginosa）和棘狀阿米巴原蟲（Acanthamoeba）", "角膜塑型術造成角膜炎的比例高出其他隱形眼鏡許多", "使用自來水沖洗不會有影響", "隱形眼鏡盒大約兩年更換一次即可"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00753', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡所造成的角膜乾燥（cornealdesiccation），下列何者錯誤？', '["和鏡片材質和鏡片邊緣設計相關", "又叫做6-12點鐘角膜染色（6and12o’clockstaining）", "在硬式隱形眼鏡使用者發生率可高達40%-90%", "長戴型（extended-wear）隱形眼鏡的發生率高於日戴型（daily-wear）隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00754', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式非球面多焦隱形眼鏡，下列敘述何者錯誤？', '["偏心率（eccentricity）愈高，可以矯正的老花度數愈高", "以後表面為非球面設計（back-surfaceasphericdesign）的鏡片，愈往周邊愈平坦，可形成負球面像差", "非球面設計是運用同步視覺原理，遠和近的影像會同時進入瞳孔，有些人在晚上會出現光暈或鬼影", "配戴時眨眼，鏡片移動不要超過1.5mm，較平的角膜，對於老花的矯正，驗配較容易失敗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00755', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關老花隱形眼鏡之敘述，下列何者錯誤？', '["材質的改變、透氧度的增加、可拋棄的特性，讓適合戴老花軟式隱形眼鏡的人越來越多", "軟式老花隱形眼鏡最常用的設計是同步視覺設計（simultaneousvisiondesign）", "在硬式老花隱形眼鏡中，轉換（translating）設計對於增加看近的視力提供相當大的好處", "轉換設計的視力品質比同步視覺設計差，所以僅很少的軟式老花隱形眼鏡中使用轉換設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00756', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式轉換型雙焦隱形眼鏡（translatingbifocal）之驗配評估，下列處理方式何者錯誤？', '["評估硬式轉換型雙焦隱形眼鏡時，其鏡片的位置太高時，則可將鏡片的稜鏡（prism）增加0.50∆", "評估硬式轉換型雙焦隱形眼鏡時，其鏡片過度旋轉（excessiverotation），則可將鏡片的基弧調整更陡0.50D", "評估硬式轉換型雙焦隱形眼鏡時，配戴者反應看遠方時的視力較為模糊，評估檢查時發現鏡片太小無法 覆蓋瞳孔，則可將鏡片的總直徑加大", "評估硬式轉換型雙焦隱形眼鏡時，配戴者反應看近方時的視力較為模糊，評估檢查時發現鏡片在轉換遠 方及近方度數時轉換不理想，則可增加鏡片的邊緣間隙（edgeclearance）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00757', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於增強型單眼視（enhanced monovision）與改良型單眼視（modified monovision）、部份單眼視（partial monovision）之敘述，下列何者錯誤？', '["增強型單眼視，最常見的方法是用單光（single-vision）看遠距離的度數鏡片配戴於優勢眼（dominanteye）， 用多焦點鏡片配戴於非優勢眼", "增強型單眼視，可將優勢眼配戴看近距離的單光度數鏡片，非優勢眼配戴遠距離多焦點鏡片，藉以改善 近距離視力", "改良型單眼視，為一眼配戴中心看遠的同步視覺設計（simultaneousdesign）的鏡片，另一眼為中心看近 的同步視覺設計的鏡片", "對於中距離視力需求較大的配戴者，部份單眼視為最不建議之方法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00758', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '提高單眼視覺法老花隱形眼鏡的繼續使用率及成功率，是指當老花度數多少以上時，可考慮加以輔助眼鏡 之使用？', '["+0.75D", "+1.00D", "+1.50D", "+2.00D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
